import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{o as n,c as e,f as l,a as s,e as i}from"./app-76dad89e.js";const c={},o=s("blockquote",null,[s("p",null,"Linux 0.11 源码阅读（及其调试），环境搭建")],-1),p=i(`<h1 id="环境搭建" tabindex="-1"><a class="header-anchor" href="#环境搭建" aria-hidden="true">#</a> 环境搭建</h1><p>建议在 <code>docker</code> 环境下搭建，构建的 <code>Dockerfile</code> 如下：</p><div class="language-docker line-numbers-mode" data-ext="docker"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">from</span><span style="color:#ABB2BF;"> ubuntu:20.04</span></span>
<span class="line"></span>
<span class="line"><span style="color:#61AFEF;">run</span><span style="color:#ABB2BF;"> sed -i </span><span style="color:#98C379;">&#39;s@//.*archive.ubuntu.com@//mirrors.ustc.edu.cn@g&#39;</span><span style="color:#ABB2BF;"> /etc/apt/sources.list &amp;&amp; \\</span></span>
<span class="line"><span style="color:#ABB2BF;">    apt-get update &amp;&amp; \\</span></span>
<span class="line"><span style="color:#ABB2BF;">    apt-get install -y --no-install-recommends \\</span></span>
<span class="line"><span style="color:#ABB2BF;">    build-essential \\</span></span>
<span class="line"><span style="color:#ABB2BF;">    ca-certificates \\</span></span>
<span class="line"><span style="color:#ABB2BF;">    curl \\</span></span>
<span class="line"><span style="color:#ABB2BF;">    wget \\</span></span>
<span class="line"><span style="color:#ABB2BF;">    unzip \\</span></span>
<span class="line"><span style="color:#ABB2BF;">    git \\</span></span>
<span class="line"><span style="color:#ABB2BF;">    libssl-dev \\</span></span>
<span class="line"><span style="color:#ABB2BF;">    pkg-config \\</span></span>
<span class="line"><span style="color:#ABB2BF;">    qemu \\</span></span>
<span class="line"><span style="color:#ABB2BF;">    qemu-system \\</span></span>
<span class="line"><span style="color:#ABB2BF;">    gcc \\</span></span>
<span class="line"><span style="color:#ABB2BF;">    gdb</span></span>
<span class="line"></span>
<span class="line"><span style="color:#61AFEF;">workdir</span><span style="color:#ABB2BF;"> /root/</span></span>
<span class="line"></span>
<span class="line"><span style="color:#61AFEF;">run</span><span style="color:#ABB2BF;"> wget https://github.com/yuan-xy/Linux-0.11/archive/refs/heads/master.zip &amp;&amp; \\</span></span>
<span class="line"><span style="color:#ABB2BF;">    mv master.zip linux-0.11.zip &amp;&amp; \\</span></span>
<span class="line"><span style="color:#ABB2BF;">    unzip linux-0.11.zip</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这里考虑到从 <a href="kernel.org">原版</a> 开始构建会比较麻烦，毕竟 <code>Linux 0.11</code> 是很早期的版本了，所以直接用了别人修改过的项目（当然关于源码的部分是肯定没改的）</p><p>输入命令：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">docker</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">build</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">--network=host</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-t</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">linux0.11</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-f</span><span style="color:#ABB2BF;"> &lt;</span><span style="color:#98C379;">your-dockerfile-nam</span><span style="color:#ABB2BF;">e&gt; </span><span style="color:#98C379;">.</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>进行镜像的构建，然后使用命令：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">docker</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">run</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">--network=host</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-it</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">linux0.11:latest</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">/bin/bash</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>运行项目即可。</p><p>我在这里使用 <code>VS Code</code> 直接连接进入容器中，如下所示：</p><figure><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/202311172214293.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><p>然后在此终端中输入 <code>make &amp;&amp; make start</code> 即可运行。</p><h1 id="如何查看qemu的窗口" tabindex="-1"><a class="header-anchor" href="#如何查看qemu的窗口" aria-hidden="true">#</a> 如何查看qemu的窗口</h1><p>由于我们在 <code>docker</code> 中没有开启 <code>GUI</code>，所以这里 <code>qemu</code> 的窗口我们是无法直接看见的，但可以发现，<code>make satrt</code> 会开启一个 <code>vnc server</code>，在端口 <code>5900</code>，我们只需要在本机安装一个 <code>vnc client</code> 即可查看此远程桌面。</p><p>这里，我们可以选择 <code>realvnc</code>，在 <code>ArchLinux</code> 下安装：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">yay</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-S</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">realvnc-vnc-viewer</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>然后，启动此 <code>vnc viewer</code>，在 <code>url</code> 里输入 <code>localhost:5900</code> ，打开即可看见 <code>qemu</code> 的窗口：</p><figure><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/202311172219331.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><h1 id="debug" tabindex="-1"><a class="header-anchor" href="#debug" aria-hidden="true">#</a> Debug</h1><p>在 <code>Debug</code> 之前，我们需要修复一个 <code>bug</code>，修改 <code>Makefile</code> 文件中的 <code>debug</code> 部分如图：</p><figure><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/202311172221726.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><p>即，将 <code>qemu-system-x86_64</code> 修改为 <code>qemu-system-i386</code></p><p>我们可以在终端输入 <code>make debug</code> 来启动一个 <code>gdb server</code>，然后，启动另一个终端，输入：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">gdb</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">tools/system</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>进入 <code>gdb</code>，然后输入：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#abb2bf;">target remote:1234 </span></span>
<span class="line"><span style="color:#abb2bf;"></span></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>即可连接到 <code>gdb server</code>，然后输入：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">b</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">main</span></span>
<span class="line"><span style="color:#61AFEF;">c</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>即可得到下图：</p><figure><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/202311172223327.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><p>而对于 <code>qemu</code> 的窗口，应该如下所示：</p><figure><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/202311172223740.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><p>至此，环境已搭建完成。</p>`,33);function d(r,t){return n(),e("div",null,[o,l("more"),p])}const g=a(c,[["render",d],["__file","Linux-0.11-RTFSC-00.html.vue"]]);export{g as default};
